return {
  lines: empty(),
  statements: empty(),
  functions: empty(),
  branches: empty(),
  branchesTrue: empty(),
};

if (!valid) {
  throw new Error(
    "Invalid summary coverage object, missing keys, found:" +
      Object.keys(obj).join(","),
  );
}

if (!valid) {
  throw new Error(
    "Invalid file coverage object, missing keys, found:" +
      Object.keys(obj).join(","),
  );
}

try {
  return fs.readFileSync(path, "utf8");
} catch (ex) {
  throw new Error(`Unable to lookup source: ${path} (${ex.message})`);
}

if (sep === "\\") {
  pos = root.indexOf(":\\");
  if (pos >= 0) {
    root = root.substring(0, pos + 2);
  }
}

if (sep !== "/") {
  quoted = new RegExp(sep.replace(/\W/g, "\\$&"), "g");
  dir = dir.replace(quoted, "/");
  file = file.replace(quoted, "/"); // excessively paranoid?
}

["push", "pop", "shift", "unshift", "splice"].forEach((fn) => {
  Object.defineProperty(Path.prototype, fn, {
    value(...args) {
      return this.v[fn](...args);
    },
  });
});

Object.defineProperty(Path.prototype, "length", {
  enumerable: true,
  get() {
    return this.v.length;
  },
});

return paths.reduce(
  (common, path) => common.commonPrefixPath(path),
  paths[0] || new Path([]),
);

if (!parent) {
  parent = new ReportNode(parentPath);
  nodeMap[parentPath.toString()] = parent;
  created(parentPath, parent);
}

list.forEach((o) => {
  const parent = findOrCreateParent(o.path.parent(), nodeMap);
  parent.addChild(new ReportNode(o.path, o.fileCoverage));
});

if (children.length === 1 && !children[0].fileCoverage) {
  children[0].parent = parent;
  return foldIntoOneDir(children[0], parent);
}

Object.entries(lineStats).forEach(([lineNumber, count]) => {
  if (structuredText[lineNumber]) {
    structuredText[lineNumber].covered = count > 0 ? "yes" : "no";
    structuredText[lineNumber].hits = count;
  }
});

const skips = [].concat(
  countLabel(statements, "statement", "s"),
  countLabel(functions, "function", "s"),
  countLabel(branches, "branch", "es"),
);

return `
            <div class='fl pad1y'>
                <span class="strong">${skips.join(", ")}</span>
                <span class="quiet">Ignored</span>  &nbsp;&nbsp;&nbsp;&nbsp;
            </div>
        `;

const emptyClasses = {
  statements: "empty",
  lines: "empty",
  functions: "empty",
  branches: "empty",
};

for (const plugin of loadedPlugins) {
  if (!resolvedIds.has(plugin.id)) {
    unused.push(plugin);
  }
}

for (const plugin of unused) {
  const name =
    plugin.npmPackage !== undefined && plugin.npmPackage !== null
      ? `${plugin.npmPackage}  (id: ${plugin.id})`
      : plugin.id;
  lines.push(`  - ${name}`);
}

type HookHandlerCategoryFactories = {
  [HookCategoryNameT in keyof HardhatHooks]?: () => Promise<{
    default: HookHandlerCategoryFactory<HookCategoryNameT>;
  }>;
};

type HookHandlerCategoryFactory<
  CategoryNameT extends keyof HardhatHooks,
> = () => Promise<Partial<HardhatHooks[CategoryNameT]>>;

return (
  typeof potential === "object" &&
  potential !== null &&
  "type" in potential &&
  typeof potential.type === "string" &&
  isValidEnumValue(TaskDefinitionType, potential.type)
);

return (
  typeof potential === "object" &&
  potential !== null &&
  "type" in potential &&
  typeof potential.type === "string" &&
  isValidEnumValue(ArgumentType, potential.type) &&
  "isVariadic" in potential
);

if (paths.artifacts !== undefined) {
  validationErrors.push(...validatePath(paths.artifacts, "artifacts"));
}

if (typeof task.description !== "string") {
  validationErrors.push({
    path: [...path, "description"],
    message: "task description must be a string",
  });
}

if (task.description !== undefined && typeof task.description !== "string") {
  validationErrors.push({
    path: [...path, "description"],
    message: "task description must be a string",
  });
}

if (task.action !== undefined && task.inlineAction !== undefined) {
  validationErrors.push({
    path: [...path],
    message: 'task cannot define both "action" and "inlineAction"',
  });
}

if (isPlugin && task.inlineAction !== undefined) {
  validationErrors.push({
    path: [...path, "inlineAction"],
    message:
      "plugins cannot use inline actions. Use a lazy action import instead",
  });
}
